<template>
  <div class="symbol-info">
    <div class="symbol-info__container">
      <div class="symbol-info__choice mr10">
        Текущий символ:
        <select class="symbol-info__select" v-model="currentSymbol" @change="change()">
          <option  class="symbol-info__option" v-for="symbol of symbols" :key="symbol">{{symbol}}</option>
        </select>
      </div>
      <div class="symbol-info__table">
        <div class="symbol-info__row-header">
          <div class="symbol-info__col">bidPrice</div>
          <div class="symbol-info__col">bidQty</div>
          <div class="symbol-info__col">askPrice</div>
          <div class="symbol-info__col">askQty</div>
        </div>
        <div class="symbol-info__row" v-if="getDropList">
          <div class="symbol-info__col">{{+getDropList.bidPrice}}</div>
          <div class="symbol-info__col">{{+getDropList.bidQty}}</div>
          <div class="symbol-info__col">{{+getDropList.askPrice}}</div>
          <div class="symbol-info__col">{{+getDropList.askQty}}</div>
        </div>
      </div>
    </div>
    
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
export default {
  data: () => ({
    currentSymbol: '',
    symbols: ['btcusdt', 'bnbbtc', 'ethbtc']
  }),
  computed: {
    ...mapGetters(['getSymbol', 'getDropList'])
  },
  mounted() {
    this.currentSymbol = this.getSymbol
    this.fetchDropList(this.currentSymbol)
  },
  methods: {
     change() {
      this.changeSymbol(this.currentSymbol)
      this.fetchDropList()
    },
    ...mapActions(['changeSymbol', 'fetchDropList'])
  }
}
</script>

<style lang="scss">
.symbol-info{
  &__container {
    padding-top: 25px;
    display: flex;
    justify-content: center;
    align-items: center;
  }
  &__choice {
    min-width: 210px;
  }
  &__select{
    font-size: 17px;
    display: inline-block;
  }
  &__table{
    background-color: #ffe633;
    padding: 10px;
    border-radius: 6px;
    box-shadow: 0px 0px 5px 1px;
    width: 400px;
  }
  &__row-header {
    border-bottom: 1px solid black;
    margin-bottom: 5px;
  }
  &__row-header, &__row{
    display: grid;
    justify-items: start;
    grid-template-columns: repeat(4, 1fr);
  }

  @media screen and (max-width: 760px) {
    &__container {
      flex-direction: column;
    }
    &__choice{
      margin-bottom: 10px;
    }
  }
  
}
</style>